// Java 11 avec Weka (bibliothèque ML la plus populaire en Java)
// Dépendance Maven : weka-stable:3.8.6
import weka.classifiers.trees.RandomForest;
import weka.core.*;
import java.util.ArrayList;

public class PremierClassifieur {
    public static void main(String[] args) throws Exception {
        // Définir les attributs : heures_etude, heures_sommeil, resultat
        ArrayList<Attribute> attrs = new ArrayList<>();
        attrs.add(new Attribute("heures_etude"));
        attrs.add(new Attribute("heures_sommeil"));
        ArrayList<String> classes = new ArrayList<>();
        classes.add("echec");
        classes.add("succes");
        attrs.add(new Attribute("resultat", classes));

        // Créer le dataset et ajouter les données
        Instances dataset = new Instances("Apprentissage", attrs, 5);
        dataset.setClassIndex(2);

        // Données : [heures_étude, heures_sommeil, résultat]
        double[][] data = {{2,5,0},{8,7,1},{3,4,0},{9,8,1},{1,3,0}};
        for (double[] row : data)
            dataset.add(new DenseInstance(1.0, row));

        // Entraîner le classifieur Random Forest
        RandomForest clf = new RandomForest();
        clf.buildClassifier(dataset);

        // Prédiction : 7h d'étude, 8h de sommeil
        DenseInstance test = new DenseInstance(1.0, new double[]{7, 8, 0});
        test.setDataset(dataset);
        double result = clf.classifyInstance(test);
        System.out.println("Prédiction : "
            + dataset.classAttribute().value((int) result));
        // -> succes prédit !
    }
}

public class VecteursEtOperations {
    public static void main(String[] args) {
        // Un vecteur représente un point dans l'espace
        double[] prix  = {150, 200, 80};     // 3 produits
        double[] poids = {0.5, 0.3, 0.2};   // importance de chaque produit

        // Produit scalaire : mesure de similarité / pondération
        double score = dot(prix, poids);
        System.out.printf("Score pondéré : %.1f%n", score); // 151.0

        // Norme : 'longueur' d'un vecteur
        System.out.printf("Norme : %.2f%n", norm(prix));    // 266.27

        // Cosine similarity : angle entre vecteurs (utilisé en NLP !)
        double[] v1 = {1, 2, 3};
        double[] v2 = {2, 4, 6};   // même direction
        double cosSim = dot(v1, v2) / (norm(v1) * norm(v2));
        System.out.printf("Similarité cosinus : %.4f%n", cosSim); // 1.0000
    }

    static double dot(double[] a, double[] b) {
        double s = 0;
        for (int i = 0; i < a.length; i++) s += a[i] * b[i];
        return s;
    }

    static double norm(double[] v) {
        double s = 0;
        for (double x : v) s += x * x;
        return Math.sqrt(s);
    }
}

public class MatricesCoucheNeuronale {
    public static void main(String[] args) {
        // Une couche dense = multiplication matricielle + biais
        // Entrée : 3 features, Sortie : 2 neurones
        double[][] W = {{0.2, -0.1}, {0.5, 0.3}, {-0.2, 0.8}}; // poids (3x2)
        double[]   b = {0.1, -0.2};                              // biais
        double[]   x = {1.0, 2.0, 3.0};                         // entrée

        // Forward pass : x @ W + b
        double[] output = new double[2];
        for (int j = 0; j < 2; j++) {
            output[j] = b[j];
            for (int i = 0; i < 3; i++) output[j] += x[i] * W[i][j];
        }
        System.out.printf("Sortie de la couche : [%.1f, %.1f]%n",
            output[0], output[1]); // [0.7, 2.7]

        // C'est exactement ce que fait une Dense layer en DL4J :
        // new DenseLayer.Builder().nIn(3).nOut(2).build()
    }
}

// Java 11 avec Apache Commons Math 3
// Dépendance Maven : commons-math3:3.6.1
import org.apache.commons.math3.linear.*;

public class SVDExemple {
    public static void main(String[] args) {
        // Matrice films x utilisateurs (notes 0-5)
        double[][] data = {
            {5, 4, 0, 1},  // Alice
            {4, 5, 0, 2},  // Bob  (similaire à Alice)
            {0, 1, 5, 4},  // Carol
            {1, 0, 4, 5},  // Dave (similaire à Carol)
        };

        RealMatrix ratings = MatrixUtils.createRealMatrix(data);
        SingularValueDecomposition svd = new SingularValueDecomposition(ratings);

        // U : embeddings utilisateurs, S : importance, Vt : embeddings films
        double[] S = svd.getSingularValues();
        System.out.print("Dimensions latentes : [");
        for (int i = 0; i < S.length; i++)
            System.out.printf("%.2f%s", S[i], i < S.length - 1 ? ", " : "]%n");
        // -> 2 concepts principaux : films d'action vs films romantiques
    }
}

import java.util.Arrays;

public class Distributions {
    public static void main(String[] args) {
        String[] vocabulaire = {"chat", "chien", "oiseau", "poisson"};
        double[] logits = {3.2, 1.5, 0.8, 0.3};

        // Softmax : convertit en probabilités (somme = 1)
        double[] probs = softmax(logits);
        for (int i = 0; i < vocabulaire.length; i++) {
            String bar = "█".repeat((int)(probs[i] * 20));
            System.out.printf("%-10s : %.1f%% %s%n",
                vocabulaire[i], probs[i] * 100, bar);
        }

        // Température : contrôle la 'créativité'
        // T=0.5 -> plus déterministe  |  T=2.0 -> plus aléatoire
        System.out.println();
        System.out.println("Avec température T=0.5 :");
        double[] scaled = Arrays.stream(logits).map(x -> x / 0.5).toArray();
        double[] probsCold = softmax(scaled);
        for (int i = 0; i < vocabulaire.length; i++)
            System.out.printf("%-10s : %.1f%%%n",
                vocabulaire[i], probsCold[i] * 100);
    }

    static double[] softmax(double[] x) {
        double max = Arrays.stream(x).max().orElse(0);
        double[] exp = Arrays.stream(x).map(v -> Math.exp(v - max)).toArray();
        double sum = Arrays.stream(exp).sum();
        return Arrays.stream(exp).map(v -> v / sum).toArray();
    }
}

public class FonctionsDePerte {
    public static void main(String[] args) {
        // 1. MSE (Mean Squared Error) — pour la régression
        double[] yTrue = {3.0, 5.0, 2.0, 8.0};
        double[] yPred = {2.5, 5.5, 2.2, 7.5};
        System.out.printf("MSE : %.4f%n", mse(yTrue, yPred)); // 0.1850

        // 2. Cross-Entropy — pour la classification
        // Exemple : classer entre chat/chien
        double[] yTrueOH    = {1, 0};       // c'est un chat
        double[] yPredProba = {0.8, 0.2};   // modèle dit : 80% chat

        double loss = crossEntropy(yTrueOH, yPredProba);
        System.out.printf("Cross-Entropy : %.4f%n", loss); // 0.2231 (bonne)

        double[] yPredMauvais = {0.1, 0.9};
        double lossMauvais = crossEntropy(yTrueOH, yPredMauvais);
        System.out.printf("Mauvaise prédiction : %.4f%n", lossMauvais); // 2.3026
    }

    static double mse(double[] t, double[] p) {
        double s = 0;
        for (int i = 0; i < t.length; i++) s += Math.pow(t[i] - p[i], 2);
        return s / t.length;
    }

    static double crossEntropy(double[] t, double[] p) {
        double s = 0;
        for (int i = 0; i < t.length; i++) s += t[i] * Math.log(p[i] + 1e-8);
        return -s;
    }
}

public class GradientDescent {
    static double loss(double w)     { return Math.pow(w - 3, 2); }
    static double gradient(double w) { return 2 * (w - 3); }

    public static void main(String[] args) {
        // Trouver w qui minimise L(w) = (w - 3)^2
        double w  = -2.0;  // point de départ aléatoire
        double lr = 0.1;   // learning rate (taille du pas)
        int nIter = 30;    // nombre d'itérations

        System.out.printf("Départ : w=%.2f, perte=%.2f%n", w, loss(w));
        for (int i = 0; i < nIter; i++) {
            double grad = gradient(w);
            w = w - lr * grad;   // mise à jour du paramètre
            if (i % 5 == 0)
                System.out.printf("Iter %2d: w=%.4f, perte=%.6f%n",
                    i + 1, w, loss(w));
        }
        System.out.printf("%nConvergé vers w=%.4f (optimal: 3.0)%n", w);
    }
}

public class AdamOptimizer {
    private final double lr, beta1, beta2, eps;
    private double m = 0, v = 0;
    private int t = 0;

    AdamOptimizer(double lr, double beta1, double beta2, double eps) {
        this.lr = lr; this.beta1 = beta1; this.beta2 = beta2; this.eps = eps;
    }

    double step(double grad, double param) {
        t++;
        m = beta1 * m + (1 - beta1) * grad;
        v = beta2 * v + (1 - beta2) * grad * grad;
        // Correction du biais (important aux premières itérations)
        double mHat = m / (1 - Math.pow(beta1, t));
        double vHat = v / (1 - Math.pow(beta2, t));
        return param - lr * mHat / (Math.sqrt(vHat) + eps);
    }

    public static void main(String[] args) {
        // Hyperparamètres par défaut d'Adam
        AdamOptimizer opt = new AdamOptimizer(0.01, 0.9, 0.999, 1e-8);
        double w = -2.0;
        for (int i = 0; i < 100; i++)
            w = opt.step(2 * (w - 3), w);  // gradient de (w-3)^2
        System.out.printf("Adam convergé: w=%.6f%n", w); // ~3.000000
    }
}

// Java 11 avec Weka (weka-stable:3.8.6)
import weka.classifiers.functions.LinearRegression;
import weka.classifiers.functions.Logistic;
import weka.classifiers.evaluation.Evaluation;
import weka.core.*;
import java.util.*;

public class RegressionLineaireLogistique {
    public static void main(String[] args) throws Exception {
        // ── RÉGRESSION LINÉAIRE ──────────────────────────
        // Prédire le prix d'une maison (en k€)
        ArrayList<Attribute> attrsReg = new ArrayList<>();
        attrsReg.add(new Attribute("surface"));
        attrsReg.add(new Attribute("nb_pieces"));
        attrsReg.add(new Attribute("prix"));

        Instances dataReg = new Instances("Maisons", attrsReg, 5);
        dataReg.setClassIndex(2);

        double[][] maisons = {{50,2,90},{100,4,175},{150,5,250},{80,3,130},{120,4,200}};
        for (double[] row : maisons) dataReg.add(new DenseInstance(1.0, row));

        LinearRegression linReg = new LinearRegression();
        linReg.buildClassifier(dataReg);
        System.out.println("Modèle linéaire appris !");

        // Prédiction : 90m², 3 pièces
        DenseInstance test = new DenseInstance(1.0, new double[]{90, 3, 0});
        test.setDataset(dataReg);
        System.out.printf("Prix estimé : %.0f k€%n",
            linReg.classifyInstance(test));

        // ── RÉGRESSION LOGISTIQUE ────────────────────────
        // Prédire si un client va churner (0/1)
        ArrayList<Attribute> attrsClf = new ArrayList<>();
        attrsClf.add(new Attribute("age"));
        attrsClf.add(new Attribute("depense_mensuelle"));
        attrsClf.add(new Attribute("nb_reclamations"));
        List<String> cls = Arrays.asList("reste", "churne");
        attrsClf.add(new Attribute("churn", cls));

        Instances dataClf = new Instances("Churn", attrsClf, 6);
        dataClf.setClassIndex(3);
        double[][] clients = {{45,600,0,0},{30,280,3,1},{55,750,1,0},
                               {25,200,5,1},{40,500,0,0},{35,300,2,1}};
        for (double[] row : clients) dataClf.add(new DenseInstance(1.0, row));

        Logistic logReg = new Logistic();
        logReg.buildClassifier(dataClf);

        Evaluation eval = new Evaluation(dataClf);
        eval.evaluateModel(logReg, dataClf);
        System.out.printf("Accuracy churn: %.1f%%%n", eval.pctCorrect());
    }
}

// Java 11 avec Weka (weka-stable:3.8.6)
import weka.classifiers.trees.RandomForest;
import weka.classifiers.evaluation.Evaluation;
import weka.classifiers.meta.Bagging;
import weka.core.*;
import java.util.*;

public class RandomForestImportance {
    public static void main(String[] args) throws Exception {
        // Génération d'un dataset de classification (10 features)
        int nFeatures = 10;
        ArrayList<Attribute> attrs = new ArrayList<>();
        for (int i = 0; i < nFeatures; i++) attrs.add(new Attribute("feature_" + i));
        List<String> cls = Arrays.asList("classe0", "classe1");
        attrs.add(new Attribute("label", cls));

        Instances data = new Instances("Classification", attrs, 1000);
        data.setClassIndex(nFeatures);

        Random rng = new Random(42);
        for (int i = 0; i < 1000; i++) {
            double[] row = new double[nFeatures + 1];
            for (int j = 0; j < nFeatures; j++) row[j] = rng.nextGaussian();
            row[nFeatures] = (row[0] + row[1] > 0) ? 1 : 0; // features 0+1 sont informatives
            data.add(new DenseInstance(1.0, row));
        }

        // Random Forest avec cross-validation 5 folds
        RandomForest rf = new RandomForest();
        rf.setNumIterations(100);
        rf.buildClassifier(data);

        Evaluation eval = new Evaluation(data);
        eval.crossValidateModel(rf, data, 5, new Random(42));
        System.out.printf("Random Forest : %.3f (5-fold CV)%n",
            eval.pctCorrect() / 100);

        // Gradient Boosting avec Weka (AdaBoost ou Bagging)
        Bagging gb = new Bagging();
        gb.setNumIterations(100);
        gb.buildClassifier(data);
        Evaluation evalGb = new Evaluation(data);
        evalGb.crossValidateModel(gb, data, 5, new Random(42));
        System.out.printf("Gradient Boosting : %.3f%n",
            evalGb.pctCorrect() / 100);

        System.out.println();
        System.out.println("Pour l'importance des features en Java :");
        System.out.println("  weka.attributeSelection.InfoGainAttributeEval");
        System.out.println("  weka.attributeSelection.ReliefFAttributeEval");
    }
}

// Java 11 avec Weka (weka-stable:3.8.6)
import weka.clusterers.SimpleKMeans;
import weka.core.*;
import weka.filters.Filter;
import weka.filters.unsupervised.attribute.Standardize;
import java.util.*;

public class KMeansSegmentation {
    public static void main(String[] args) throws Exception {
        // Simulation de données clients (2 dimensions)
        ArrayList<Attribute> attrs = new ArrayList<>();
        attrs.add(new Attribute("x"));
        attrs.add(new Attribute("y"));
        Instances clients = new Instances("Clients", attrs, 300);

        Random rng = new Random(42);
        for (int i = 0; i < 300; i++)
            clients.add(new DenseInstance(1.0,
                new double[]{rng.nextGaussian(), rng.nextGaussian()}));

        // Normalisation OBLIGATOIRE pour le clustering
        Standardize std = new Standardize();
        std.setInputFormat(clients);
        Instances clientsScaled = Filter.useFilter(clients, std);

        // K-Means : chercher 3 segments
        SimpleKMeans kmeans = new SimpleKMeans();
        kmeans.setNumClusters(3);
        kmeans.setSeed(42);
        kmeans.buildClusterer(clientsScaled);

        Instances centroids = kmeans.getClusterCentroids();
        for (int i = 0; i < centroids.numInstances(); i++) {
            System.out.printf("Segment %d: %d clients, centre=(%.2f, %.2f)%n",
                i + 1, kmeans.getClusterSizes()[i],
                centroids.instance(i).value(0),
                centroids.instance(i).value(1));
        }

        // Trouver le bon k : méthode du coude
        System.out.println();
        System.out.println("Inertie par k (cherchez le coude) :");
        for (int k = 2; k <= 9; k++) {
            SimpleKMeans km = new SimpleKMeans();
            km.setNumClusters(k);
            km.buildClusterer(clientsScaled);
            System.out.printf("  k=%d: %.1f%n", k, km.getSquaredError());
        }
    }
}

