import java.util.Random;

public class MLP {
    // Poids [layer][neurone_from][neurone_to], biais [layer][neurone]
    private final double[][][] W;
    private final double[][] b;
    double[][] activations; // pour le backprop

    MLP(int[] sizes) {
        Random rng = new Random(42);
        W = new double[sizes.length - 1][][];
        b = new double[sizes.length - 1][];
        for (int l = 0; l < sizes.length - 1; l++) {
            double scale = Math.sqrt(2.0 / sizes[l]); // init He (ReLU)
            W[l] = new double[sizes[l]][sizes[l + 1]];
            b[l] = new double[sizes[l + 1]];
            for (int i = 0; i < sizes[l]; i++)
                for (int j = 0; j < sizes[l + 1]; j++)
                    W[l][i][j] = rng.nextGaussian() * scale;
        }
    }

    static double relu(double x)    { return Math.max(0, x); }
    static double sigmoid(double x) { return 1 / (1 + Math.exp(-x)); }

    double[] forward(double[] x) {
        activations = new double[W.length + 1][];
        activations[0] = x;
        double[] cur = x;
        for (int l = 0; l < W.length; l++) {
            double[] next = new double[b[l].length];
            for (int j = 0; j < next.length; j++) {
                next[j] = b[l][j];
                for (int i = 0; i < cur.length; i++) next[j] += cur[i] * W[l][i][j];
                // ReLU pour couches cachées, Sigmoid en sortie
                next[j] = (l < W.length - 1) ? relu(next[j]) : sigmoid(next[j]);
            }
            activations[l + 1] = next;
            cur = next;
        }
        return cur;
    }

    public static void main(String[] args) {
        // Architecture : 2 entrées -> 4 neurones -> 3 neurones -> 1 sortie
        MLP mlp = new MLP(new int[]{2, 4, 3, 1});
        double[] output = mlp.forward(new double[]{0.5, -0.3});
        System.out.printf("Prédiction : %.4f%n", output[0]);

        int total = 0;
        for (int l = 0; l < mlp.W.length; l++)
            total += mlp.W[l].length * mlp.W[l][0].length + mlp.b[l].length;
        System.out.println("Paramètres totaux : " + total);
    }
}

import java.util.Random;
import java.util.function.DoubleUnaryOperator;

public class Backprop {
    // Architecture 2 -> 3 -> 1 sur le problème XOR
    public static void main(String[] args) {
        Random rng = new Random(0);
        double[][] W1 = randn(rng, 2, 3, 0.1), W2 = randn(rng, 3, 1, 0.1);
        double[]   b1 = new double[3],           b2 = new double[1];

        double[][] X = {{0,0},{0,1},{1,0},{1,1}};
        double[][] y = {{0},  {1},  {1},  {0}};

        double lr = 0.5, finalLoss = 0;

        for (int epoch = 0; epoch < 5000; epoch++) {
            // ─── FORWARD PASS ────────────────────────────
            double[][] z1 = addB(mul(X, W1), b1), a1 = applyFn(z1, Backprop::sig);
            double[][] z2 = addB(mul(a1, W2), b2), a2 = applyFn(z2, Backprop::sig);

            // Perte MSE
            finalLoss = 0;
            for (double[] row : sub(a2, y)) for (double v : row) finalLoss += v * v;
            finalLoss /= X.length;

            // ─── BACKWARD PASS ───────────────────────────
            double[][] dL  = scale(sub(a2, y), 2.0 / X.length);
            double[][] dZ2 = hadamard(dL, applyFn(z2, Backprop::sigD));
            double[][] dW2 = mul(T(a1), dZ2);
            double[]   db2 = colSum(dZ2);
            double[][] dZ1 = hadamard(mul(dZ2, T(W2)), applyFn(z1, Backprop::sigD));
            double[][] dW1 = mul(T(X), dZ1);
            double[]   db1 = colSum(dZ1);

            // ─── MISE À JOUR DES POIDS ───────────────────
            W2 = sub2(W2, scale(dW2, lr));  W1 = sub2(W1, scale(dW1, lr));
            for (int j = 0; j < b2.length; j++) b2[j] -= lr * db2[j];
            for (int j = 0; j < b1.length; j++) b1[j] -= lr * db1[j];
        }

        System.out.printf("Perte finale : %.6f%n", finalLoss);
        double[][] pred = applyFn(addB(mul(applyFn(addB(mul(X,W1),b1),Backprop::sig),W2),b2),Backprop::sig);
        System.out.print("Prédictions XOR : [");
        for (int i = 0; i < 4; i++) {
            if (i < 3) System.out.printf("%.3f, ", pred[i][0]);
            else System.out.printf("%.3f]%n", pred[i][0]);
        }
        // Attendu : [~0, ~1, ~1, ~0]
    }

    static double sig(double x)  { return 1 / (1 + Math.exp(-x)); }
    static double sigD(double x) { double s = sig(x); return s * (1 - s); }

    static double[][] randn(Random r, int rows, int cols, double s) {
        double[][] M = new double[rows][cols];
        for (int i = 0; i < rows; i++) for (int j = 0; j < cols; j++) M[i][j] = r.nextGaussian() * s;
        return M;
    }
    static double[][] mul(double[][] A, double[][] B) {
        double[][] C = new double[A.length][B[0].length];
        for (int i = 0; i < A.length; i++) for (int j = 0; j < B[0].length; j++)
            for (int k = 0; k < B.length; k++) C[i][j] += A[i][k] * B[k][j];
        return C;
    }
    static double[][] addB(double[][] M, double[] b) {
        double[][] R = new double[M.length][M[0].length];
        for (int i = 0; i < M.length; i++) for (int j = 0; j < M[0].length; j++) R[i][j] = M[i][j] + b[j];
        return R;
    }
    static double[][] applyFn(double[][] M, DoubleUnaryOperator f) {
        double[][] R = new double[M.length][M[0].length];
        for (int i = 0; i < M.length; i++) for (int j = 0; j < M[0].length; j++) R[i][j] = f.applyAsDouble(M[i][j]);
        return R;
    }
    static double[][] hadamard(double[][] A, double[][] B) {
        double[][] R = new double[A.length][A[0].length];
        for (int i = 0; i < A.length; i++) for (int j = 0; j < A[0].length; j++) R[i][j] = A[i][j] * B[i][j];
        return R;
    }
    static double[][] T(double[][] M) {
        double[][] R = new double[M[0].length][M.length];
        for (int i = 0; i < M.length; i++) for (int j = 0; j < M[0].length; j++) R[j][i] = M[i][j];
        return R;
    }
    static double[][] sub(double[][] A, double[][] B) {
        double[][] R = new double[A.length][A[0].length];
        for (int i = 0; i < A.length; i++) for (int j = 0; j < A[0].length; j++) R[i][j] = A[i][j] - B[i][j];
        return R;
    }
    static double[][] sub2(double[][] A, double[][] B) { return sub(A, B); }
    static double[][] scale(double[][] M, double s) {
        double[][] R = new double[M.length][M[0].length];
        for (int i = 0; i < M.length; i++) for (int j = 0; j < M[0].length; j++) R[i][j] = M[i][j] * s;
        return R;
    }
    static double[] colSum(double[][] M) {
        double[] s = new double[M[0].length];
        for (double[] row : M) for (int j = 0; j < row.length; j++) s[j] += row[j];
        return s;
    }
}

