import org.deeplearning4j.nn.conf.*;
import org.deeplearning4j.nn.conf.layers.*;
import org.deeplearning4j.nn.multilayer.MultiLayerNetwork;
import org.deeplearning4j.nn.weights.WeightInit;
import org.nd4j.linalg.activations.Activation;
import org.nd4j.linalg.learning.config.Adam;
import org.nd4j.linalg.lossfunctions.LossFunctions;

public class RegularisationDL4J {
    public static void main(String[] args) {
        // Modèle AVEC régularisation (DL4J)
        MultiLayerConfiguration conf = new NeuralNetConfiguration.Builder()
            .seed(42)
            .updater(new Adam(0.001))
            .weightInit(WeightInit.HE_UNIFORM)
            .l2(0.001)   // L2 regularization (weight decay) globale
            .list()
            // Dense(256) + Dropout(0.3)
            .layer(new DenseLayer.Builder()
                .nIn(20).nOut(256).activation(Activation.RELU).build())
            .layer(new DropoutLayer.Builder(0.7).build()) // keep = 0.7
            // BatchNormalization : stabilise les activations
            .layer(new BatchNormalization.Builder().build())
            .layer(new DenseLayer.Builder()
                .nIn(256).nOut(256).activation(Activation.RELU).build())
            .layer(new DropoutLayer.Builder(0.7).build())
            // Couche de sortie
            .layer(new OutputLayer.Builder(LossFunctions.LossFunction.XENT)
                .nIn(256).nOut(1).activation(Activation.SIGMOID).build())
            .build();

        MultiLayerNetwork model = new MultiLayerNetwork(conf);
        model.init();
        System.out.println("Paramètres : " + model.numParams());

        System.out.println();
        System.out.println("Techniques clés anti-overfitting :");
        System.out.println("  1. Plus de données (le meilleur remède)");
        System.out.println("  2. Dropout (0.2-0.5 selon la couche)");
        System.out.println("  3. L2 regularization (weight decay = 1e-4 à 1e-2)");
        System.out.println("  4. Early stopping");
        System.out.println("  5. Data augmentation (pour les images/textes)");
    }
}

// Java 11 avec Deeplearning4j (DL4J)
import org.deeplearning4j.nn.conf.*;
import org.deeplearning4j.nn.conf.inputs.InputType;
import org.deeplearning4j.nn.conf.layers.*;
import org.deeplearning4j.nn.multilayer.MultiLayerNetwork;
import org.nd4j.linalg.activations.Activation;
import org.nd4j.linalg.learning.config.Adam;
import org.nd4j.linalg.lossfunctions.LossFunctions;

public class CNNCifar10 {
    public static void main(String[] args) throws Exception {
        String[] classNames = {"avion","voiture","oiseau","chat","cerf",
                               "chien","grenouille","cheval","bateau","camion"};

        // Architecture CNN (images 32x32 RGB, 3 canaux)
        MultiLayerConfiguration conf = new NeuralNetConfiguration.Builder()
            .seed(42)
            .updater(new Adam(1e-3))
            .list()
            // Bloc 1 : détecter des features simples
            .layer(new ConvolutionLayer.Builder(3, 3).nIn(3).nOut(32)
                .activation(Activation.RELU).padding(1, 1).build())
            .layer(new BatchNormalization.Builder().build())
            .layer(new SubsamplingLayer.Builder(SubsamplingLayer.PoolingType.MAX)
                .kernelSize(2, 2).stride(2, 2).build()) // 32x32 -> 16x16
            .layer(new DropoutLayer.Builder(0.75).build())

            // Bloc 2 : features plus complexes
            .layer(new ConvolutionLayer.Builder(3, 3).nIn(32).nOut(64)
                .activation(Activation.RELU).padding(1, 1).build())
            .layer(new BatchNormalization.Builder().build())
            .layer(new SubsamplingLayer.Builder(SubsamplingLayer.PoolingType.MAX)
                .kernelSize(2, 2).stride(2, 2).build()) // 16x16 -> 8x8

            // GlobalAveragePooling : agrège spatialement
            .layer(new GlobalPoolingLayer.Builder(PoolingType.AVG).build())

            // Classificateur : 256 neurones -> 10 classes
            .layer(new DenseLayer.Builder().nIn(64).nOut(256)
                .activation(Activation.RELU).build())
            .layer(new DropoutLayer.Builder(0.5).build())
            .layer(new OutputLayer.Builder(LossFunctions.LossFunction.MCXENT)
                .nIn(256).nOut(10).activation(Activation.SOFTMAX).build())
            .setInputType(InputType.convolutional(32, 32, 3))
            .build();

        MultiLayerNetwork model = new MultiLayerNetwork(conf);
        model.init();
        System.out.println(model.summary());
        // ~80% accuracy sur CIFAR-10 en ~20 epochs avec DL4J
    }
}

