import org.deeplearning4j.nn.graph.ComputationGraph;
import org.deeplearning4j.nn.transferlearning.*;
import org.deeplearning4j.zoo.ZooModel;
import org.deeplearning4j.zoo.model.VGG16;
import org.nd4j.linalg.activations.Activation;
import org.nd4j.linalg.learning.config.Adam;
import org.nd4j.linalg.lossfunctions.LossFunctions;

public class TransferLearning {
    public static void main(String[] args) throws Exception {
        // Charger VGG16 pré-entraîné sur ImageNet (1.4M images, 1000 classes)
        ZooModel<?> zooModel = VGG16.builder().build();
        ComputationGraph vgg16 = (ComputationGraph) zooModel.initPretrained();

        // Phase 1 : Feature extraction (geler les poids de base)
        FineTuneConfiguration fineTuneConf = new FineTuneConfiguration.Builder()
            .updater(new Adam(1e-3))
            .build();

        ComputationGraph model = new TransferLearning.GraphBuilder(vgg16)
            .fineTuneConfiguration(fineTuneConf)
            .setFeatureExtractor("block5_pool")       // geler tout jusqu'ici
            .removeVertexKeepConnections("predictions")
            // Nouvelle tête pour 5 classes personnalisées
            .addLayer("fc_custom",
                new DenseLayer.Builder().nIn(4096).nOut(256)
                    .activation(Activation.RELU).build(), "fc2")
            .addLayer("output",
                new OutputLayer.Builder(LossFunctions.LossFunction.MCXENT)
                    .nIn(256).nOut(5)
                    .activation(Activation.SOFTMAX).build(), "fc_custom")
            .build();

        System.out.println("Phase 1 : Feature extraction (backbone gelé)");
        System.out.println("Paramètres entraînables : " + model.numParams());

        // Phase 2 : dégeler les dernières couches, lr plus faible
        System.out.println();
        System.out.println("Phase 2 : Fine-tuning avec lr=1e-5");
        System.out.println("Résultat typique : 90%+ accuracy avec 500 images/classe !");
    }
}

// Java 11 avec Deeplearning4j (DL4J)
import org.deeplearning4j.nn.conf.NeuralNetConfiguration;
import org.deeplearning4j.nn.conf.layers.LSTM;
import org.deeplearning4j.nn.conf.layers.RnnOutputLayer;
import org.deeplearning4j.nn.multilayer.MultiLayerNetwork;
import org.deeplearning4j.optimize.listeners.ScoreIterationListener;
import org.nd4j.linalg.activations.Activation;
import org.nd4j.linalg.api.ndarray.INDArray;
import org.nd4j.linalg.dataset.DataSet;
import org.nd4j.linalg.factory.Nd4j;
import org.nd4j.linalg.learning.config.Adam;
import org.nd4j.linalg.lossfunctions.LossFunctions;

public class LSTMSeries {

    static final int SEQ_LEN   = 30;  // fenêtre temporelle
    static final int N_HIDDEN  = 64;  // cellules LSTM
    static final int N_FEATURES = 1;  // un seul indicateur (prix normalisé)

    public static void main(String[] args) throws Exception {

        // ── Architecture LSTM ──────────────────────
        MultiLayerNetwork model = new MultiLayerNetwork(
            new NeuralNetConfiguration.Builder()
                .updater(new Adam(1e-3))
                .list()
                // Couche 1 : LSTM avec 64 cellules
                .layer(new LSTM.Builder()
                    .nIn(N_FEATURES).nOut(N_HIDDEN)
                    .activation(Activation.TANH)
                    .build())
                // Couche 2 : LSTM avec 32 cellules
                .layer(new LSTM.Builder()
                    .nIn(N_HIDDEN).nOut(32)
                    .activation(Activation.TANH)
                    .build())
                // Sortie : prédiction scalaire
                .layer(new RnnOutputLayer.Builder(
                        LossFunctions.LossFunction.MSE)
                    .nIn(32).nOut(1)
                    .activation(Activation.IDENTITY)
                    .build())
                .build());

        model.init();
        model.setListeners(new ScoreIterationListener(10));

        System.out.println("Paramètres : " + model.numParams());

        // ── Données simulées ───────────────────────
        // En pratique : charger un CSV avec nd4j.readNumpy ou Smile
        INDArray X = Nd4j.randn(new int[]{32, N_FEATURES, SEQ_LEN});
        INDArray y = Nd4j.randn(new int[]{32, 1, SEQ_LEN});

        for (int epoch = 0; epoch < 50; epoch++) {
            model.fit(new DataSet(X, y));
            model.rnnClearPreviousState();
        }

        System.out.println();
        System.out.println("Pourquoi les LSTMs ont été remplacés par les Transformers :");
        System.out.println("  - Entraînement séquentiel → pas de parallélisation GPU");
        System.out.println("  - Attention locale limitée sur de longues séquences");
        System.out.println("  - Les Transformers (2017) parallélisent tout et capturent");
        System.out.println("    des dépendances sur des milliers de tokens en même temps");
    }
}

