import org.deeplearning4j.models.word2vec.Word2Vec;
import org.deeplearning4j.text.sentenceiterator.CollectionSentenceIterator;
import org.deeplearning4j.text.tokenization.tokenizerfactory.DefaultTokenizerFactory;
import java.util.*;

public class Word2VecExemple {
    public static void main(String[] args) throws Exception {
        // Corpus (en pratique : Wikipedia entier = milliards de tokens)
        List<String> corpus = Arrays.asList(
            "chat animal domestique poil miauler",
            "chien animal domestique aboyer fidèle",
            "voiture transport moteur roues conduire",
            "vélo transport roues pédales sport",
            "roi homme château couronne pouvoir",
            "reine femme château couronne pouvoir"
        );

        // Entraîner Word2Vec
        Word2Vec model = new Word2Vec.Builder()
            .minWordFrequency(1)
            .iterations(100)
            .layerSize(100)        // dimension des vecteurs
            .windowSize(3)
            .iterate(new CollectionSentenceIterator(corpus))
            .tokenizerFactory(new DefaultTokenizerFactory())
            .build();

        model.fit();

        // Trouver les mots similaires
        System.out.println("Mots proches de 'chat' :");
        Collection<String> similars = model.wordsNearest("chat", 3);
        for (String word : similars)
            System.out.printf("  %s: %.3f%n", word, model.similarity("chat", word));

        // L'analogie célèbre : roi - homme + femme = reine
        Collection<String> analogy = model.wordsNearest(
            Arrays.asList("roi", "femme"),
            Arrays.asList("homme"),
            1);
        System.out.println();
        System.out.println("roi - homme + femme = " + analogy);
        System.out.println();
        System.out.println("Les LLMs modernes (BERT, GPT) créent des embeddings");
        System.out.println("CONTEXTUELS : le même mot a des vecteurs différents selon le contexte !");
        System.out.println("  'banque' (financière) != 'banque' (de rivière)");
    }
}

