import dev.langchain4j.model.openai.OpenAiEmbeddingModel;
import dev.langchain4j.model.embedding.EmbeddingModel;
import dev.langchain4j.data.embedding.Embedding;
import java.util.*;

public class SentenceEmbeddings {
    public static void main(String[] args) {
        // Modèle text-embedding-3-small (1536 dimensions, très performant)
        EmbeddingModel model = OpenAiEmbeddingModel.builder()
            .apiKey(System.getenv("OPENAI_API_KEY"))
            .modelName("text-embedding-3-small")
            .build();

        List<String> sentences = Arrays.asList(
            "L'IA va révolutionner la médecine",
            "L'intelligence artificielle transforme la santé",  // proche
            "J'adore les pizzas aux champignons",               // non lié
            "Le deep learning améliore le diagnostic médical"   // proche
        );

        // Encoder toutes les phrases
        List<Embedding> embeddings = model.embedAll(
            sentences.stream()
                .map(dev.langchain4j.data.segment.TextSegment::from)
                .collect(java.util.stream.Collectors.toList())
        ).content();

        System.out.println("Forme des embeddings : (" + embeddings.size()
            + ", " + embeddings.get(0).vector().length + ")");

        // Calcul de similarité cosinus entre les deux premières phrases
        float[] e0 = embeddings.get(0).vector();
        float[] e1 = embeddings.get(1).vector();
        System.out.printf("Similarité [0] vs [1] : %.3f%n",
            cosineSim(e0, e1)); // ~0.85 (très proches)

        // Application : moteur de recherche sémantique !
        System.out.println();
        System.out.println("Recherche 'IA et santé' -> phrase la plus proche trouvée automatiquement");
    }

    static float cosineSim(float[] a, float[] b) {
        float dot = 0, na = 0, nb = 0;
        for (int i = 0; i < a.length; i++) { dot += a[i]*b[i]; na += a[i]*a[i]; nb += b[i]*b[i]; }
        return dot / ((float)Math.sqrt(na) * (float)Math.sqrt(nb));
    }
}

import java.util.Arrays;
import java.util.Random;

public class SelfAttention {
    // Scaled dot-product attention
    static double[][] attention(double[][] Q, double[][] K, double[][] V) {
        int seqLen = Q.length, dK = Q[0].length;

        // Scores : Q x K^T / sqrt(d_k)
        double[][] scores = new double[seqLen][seqLen];
        for (int i = 0; i < seqLen; i++)
            for (int j = 0; j < seqLen; j++) {
                for (int k = 0; k < dK; k++) scores[i][j] += Q[i][k] * K[j][k];
                scores[i][j] /= Math.sqrt(dK);
            }

        // Softmax sur chaque ligne -> poids d'attention (somme = 1)
        double[][] weights = new double[seqLen][seqLen];
        for (int i = 0; i < seqLen; i++) {
            double max = Arrays.stream(scores[i]).max().orElse(0);
            double sum = 0;
            for (int j = 0; j < seqLen; j++) {
                weights[i][j] = Math.exp(scores[i][j] - max);
                sum += weights[i][j];
            }
            for (int j = 0; j < seqLen; j++) weights[i][j] /= sum;
        }

        // Somme pondérée des Values
        double[][] out = new double[seqLen][V[0].length];
        for (int i = 0; i < seqLen; i++)
            for (int j = 0; j < V[0].length; j++)
                for (int k = 0; k < seqLen; k++) out[i][j] += weights[i][k] * V[k][j];
        return out;
    }

    public static void main(String[] args) {
        // Simulation : 'Le chat mange la souris' (5 tokens, dim 4)
        String[] tokens = {"Le", "chat", "mange", "la", "souris"};
        int seqLen = 5, dModel = 4;

        // Matrices de projection (normalement apprises par le modèle)
        double[][] X  = randn(seqLen, dModel, 42);
        double[][] WQ = randn(dModel, dModel, 1);
        double[][] WK = randn(dModel, dModel, 2);
        double[][] WV = randn(dModel, dModel, 3);

        double[][] Q = mul(X, WQ), K = mul(X, WK), V = mul(X, WV);
        double[][] output = attention(Q, K, V);
        double[][] attnW = attention(Q, K, new double[seqLen][dModel]); // pour affichage

        // Recalculer les poids pour affichage
        double[][] scores = new double[seqLen][seqLen];
        for (int i = 0; i < seqLen; i++) for (int j = 0; j < seqLen; j++) {
            for (int k = 0; k < Q[0].length; k++) scores[i][j] += Q[i][k]*K[j][k];
            scores[i][j] /= Math.sqrt(Q[0].length);
        }
        System.out.println("Poids d'attention (quelle attention chaque token porte aux autres) :");
        for (int i = 0; i < seqLen; i++) {
            double max = Arrays.stream(scores[i]).max().orElse(0);
            double[] w = Arrays.stream(scores[i]).map(s -> Math.exp(s-max)).toArray();
            double sum = Arrays.stream(w).sum();
            int topIdx = 0;
            for (int j = 1; j < seqLen; j++) if (w[j] > w[topIdx]) topIdx = j;
            System.out.printf("  "%s" attend le plus "%s" (%.3f)%n",
                tokens[i], tokens[topIdx], w[topIdx]/sum);
        }
        System.out.println();
        System.out.println("La Multi-Head Attention utilise 8-16 têtes en parallèle,");
        System.out.println("chacune capturant différents types de relations.");
    }

    static double[][] randn(int r, int c, long seed) {
        Random rng = new Random(seed);
        double[][] M = new double[r][c];
        for (int i=0;i<r;i++) for (int j=0;j<c;j++) M[i][j]=rng.nextGaussian()*0.1;
        return M;
    }
    static double[][] mul(double[][] A, double[][] B) {
        double[][] C = new double[A.length][B[0].length];
        for (int i=0;i<A.length;i++) for (int j=0;j<B[0].length;j++)
            for (int k=0;k<B.length;k++) C[i][j]+=A[i][k]*B[k][j];
        return C;
    }
}

