import dev.langchain4j.model.openai.OpenAiChatModel;
import dev.langchain4j.model.chat.ChatLanguageModel;

public class TextGeneration {
    public static void main(String[] args) {
        String prompt = "L'intelligence artificielle va";

        // LangChain4j — génération avec différentes stratégies de décodage
        ChatLanguageModel modelCreatif = OpenAiChatModel.builder()
            .apiKey(System.getenv("OPENAI_API_KEY"))
            .modelName("gpt-4o-mini")
            .temperature(0.8)   // <1 = focalisé, >1 = créatif
            .topP(0.9)          // nucleus sampling : top 90% de la proba
            .maxTokens(80)
            .build();

        ChatLanguageModel modelDeterministe = OpenAiChatModel.builder()
            .apiKey(System.getenv("OPENAI_API_KEY"))
            .modelName("gpt-4o-mini")
            .temperature(0.0)  // greedy : toujours le token le plus probable
            .maxTokens(80)
            .build();

        System.out.println("Prompt: " + prompt);
        System.out.println();
        System.out.println("Greedy (temp=0) :");
        System.out.println(modelDeterministe.generate(prompt));
        System.out.println();
        System.out.println("Sampled (temp=0.8, top_p=0.9) :");
        System.out.println(modelCreatif.generate(prompt));

        // Stratégies de décodage disponibles :
        // temperature  : <1 = focalisé  | >1 = créatif
        // top_p        : nucleus sampling (top 90% probabilité cumulée)
        // top_k        : considérer seulement les k meilleurs tokens
        // frequencyPenalty : pénalise les répétitions
    }
}

