// Java 11 avec LangChain4j (langchain4j:0.32.0)
import dev.langchain4j.data.document.*;
import dev.langchain4j.data.document.loader.FileSystemDocumentLoader;
import dev.langchain4j.data.document.splitter.DocumentSplitters;
import dev.langchain4j.data.segment.TextSegment;
import dev.langchain4j.model.embedding.EmbeddingModel;
import dev.langchain4j.model.openai.*;
import dev.langchain4j.store.embedding.*;
import dev.langchain4j.store.embedding.inmemory.InMemoryEmbeddingStore;
import dev.langchain4j.chain.ConversationalRetrievalChain;
import java.util.List;

public class RAGLangChain4j {
    public static void main(String[] args) {
        // ─── ÉTAPE 1 : INDEXATION ────────────────────────
        List<Document> documents =
            FileSystemDocumentLoader.loadDocuments("./docs/");
        System.out.println(documents.size() + " documents chargés");

        // Chunking : chunk_size=1000, overlap=200 (évite de couper le contexte)
        DocumentSplitter splitter = DocumentSplitters.recursive(1000, 200);
        List<TextSegment> chunks = splitter.splitAll(documents);
        System.out.println(chunks.size() + " chunks créés");

        // Embeddings et base vectorielle en mémoire
        EmbeddingModel embeddingModel = OpenAiEmbeddingModel.builder()
            .apiKey(System.getenv("OPENAI_API_KEY"))
            .modelName("text-embedding-3-small")
            .build();

        EmbeddingStore<TextSegment> vectorStore = new InMemoryEmbeddingStore<>();

        EmbeddingStoreIngestor ingestor = EmbeddingStoreIngestor.builder()
            .documentSplitter(splitter)
            .embeddingModel(embeddingModel)
            .embeddingStore(vectorStore)
            .build();
        ingestor.ingest(documents);

        // ─── ÉTAPE 2 & 3 : RETRIEVAL + GENERATION ───────
        OpenAiChatModel llm = OpenAiChatModel.builder()
            .apiKey(System.getenv("OPENAI_API_KEY"))
            .modelName("gpt-4o-mini")
            .temperature(0.0)
            .build();

        ConversationalRetrievalChain chain = ConversationalRetrievalChain.builder()
            .chatLanguageModel(llm)
            .retriever(EmbeddingStoreRetriever.from(
                vectorStore, embeddingModel, 5))  // k=5 chunks les plus proches
            .build();

        String answer = chain.execute("Comment configurer l'authentification ?");
        System.out.println("Réponse: " + answer);
    }
}

// Java 11 avec LangChain4j
import dev.langchain4j.data.document.Document;
import dev.langchain4j.data.document.splitter.DocumentSplitters;
import dev.langchain4j.data.segment.TextSegment;
import java.util.List;

public class StrategiesChunking {
    public static void main(String[] args) {
        String text = "# Introduction a Spring Boot

"
            + "Spring Boot est un framework Java moderne.
"
            + "Il simplifie le developpement d'applications.

"
            + "## Installation

"
            + "Ajouter la dependance dans pom.xml

"
            + "## Premier exemple

"
            + "Creer une classe avec @SpringBootApplication...";

        Document doc = Document.from(text);

        // Stratégie 1 : Récursif (le plus courant)
        var recursive = DocumentSplitters.recursive(500, 50);
        List<TextSegment> chunksR = recursive.split(doc);
        System.out.println("Récursif : " + chunksR.size() + " chunks");

        // Stratégie 2 : Découpage sur les séparateurs de structure
        var bySection = DocumentSplitters.recursive(500, 0,
            new String[]{"## ", "# ", "

", "
", " "});
        List<TextSegment> chunksS = bySection.split(doc);
        System.out.println("Par section : " + chunksS.size() + " chunks");
        for (TextSegment seg : chunksS) {
            int end = Math.min(50, seg.text().length());
            System.out.println("  [" + seg.text().substring(0, end) + "...]");
        }

        System.out.println();
        System.out.println("Conseils de chunking :");
        System.out.println("  Documents structures (docs, wikis) -> couper sur les headers");
        System.out.println("  Texte general -> Recursif avec overlap 10-20%");
        System.out.println("  Haute precision -> Semantique (via API embedding, cout x10)");
        System.out.println("  Optimal : chunk_size 512-1024 tokens");
    }
}

// Java 11 avec LangChain4j + Chroma
import dev.langchain4j.data.embedding.Embedding;
import dev.langchain4j.data.segment.TextSegment;
import dev.langchain4j.model.embedding.EmbeddingModel;
import dev.langchain4j.model.openai.OpenAiEmbeddingModel;
import dev.langchain4j.store.embedding.EmbeddingMatch;
import dev.langchain4j.store.embedding.EmbeddingStore;
import dev.langchain4j.store.embedding.chroma.ChromaEmbeddingStore;
import java.util.List;

public class BaseVectorielleChroma {
    public static void main(String[] args) {
        // ── Embeddings OpenAI (1536 dimensions) ──────────────
        EmbeddingModel embeddingModel = OpenAiEmbeddingModel.builder()
            .apiKey(System.getenv("OPENAI_API_KEY"))
            .modelName("text-embedding-3-small")
            .build();

        // ── Connexion Chroma (serveur local) ─────────────────
        EmbeddingStore<TextSegment> store = ChromaEmbeddingStore.builder()
            .baseUrl("http://localhost:8000")
            .collectionName("documentation")
            .build();

        // ── Indexer des documents ─────────────────────────────
        List<String> documents = List.of(
            "FastAPI est un framework web Python moderne.",
            "Spring Boot simplifie le developpement d'applications Java.",
            "PostgreSQL est une base de donnees relationnelle open-source.",
            "Redis est une base de donnees cle-valeur en memoire.",
            "Docker permet de conteneuriser des applications."
        );

        for (String doc : documents) {
            TextSegment segment = TextSegment.from(doc);
            Embedding embedding = embeddingModel.embed(segment).content();
            store.add(embedding, segment);
        }
        System.out.println(documents.size() + " documents indexes");

        // ── Recherche sémantique ──────────────────────────────
        String query = "Comment deployer une application web Python ?";
        Embedding queryEmbedding = embeddingModel
            .embed(TextSegment.from(query)).content();

        List<EmbeddingMatch<TextSegment>> results =
            store.findRelevant(queryEmbedding, 3, 0.0);

        System.out.println("\nRequete : \"" + query + "\"");
        for (int i = 0; i < results.size(); i++) {
            EmbeddingMatch<TextSegment> match = results.get(i);
            String preview = match.embedded().text().substring(
                0, Math.min(60, match.embedded().text().length()));
            System.out.printf("  %d. [%.3f] %s...%n",
                i + 1, match.score(), preview);
        }
    }
}

