import dev.langchain4j.agent.tool.Tool;
import dev.langchain4j.memory.chat.MessageWindowChatMemory;
import dev.langchain4j.model.openai.OpenAiChatModel;
import dev.langchain4j.service.AiServices;
import dev.langchain4j.service.SystemMessage;

public class AgentLangChain4j {

    // Définir les outils avec l'annotation @Tool
    static class AgentTools {
        @Tool("Recherche des informations actuelles sur internet")
        public String webSearch(String query) {
            // En réalité : intégrer Tavily, SerpAPI ou DuckDuckGo
            return "Bitcoin: ~65 000 USD | 1 EUR = 1.09 USD (résultat simulé)";
        }

        @Tool("Calcule une expression mathématique")
        public double calculator(String expression) {
            // En réalité : utiliser exp4j ou ScriptEngine
            if (expression.contains("65000") && expression.contains("0.5"))
                return 65000 * 0.5 / 1.09;
            return 0;
        }
    }

    // Interface déclarative de l'agent (LangChain4j AiServices)
    interface AIAssistant {
        String chat(String userMessage);
    }

    public static void main(String[] args) {
        OpenAiChatModel model = OpenAiChatModel.builder()
            .apiKey(System.getenv("OPENAI_API_KEY"))
            .modelName("gpt-4o")
            .temperature(0.0)
            .build();

        // L'agent raisonne automatiquement et appelle les outils
        AIAssistant agent = AiServices.builder(AIAssistant.class)
            .chatLanguageModel(model)
            .tools(new AgentTools())
            .chatMemory(MessageWindowChatMemory.withMaxMessages(10))
            .build();

        String result = agent.chat(
            "Cherche le cours actuel du Bitcoin et calcule combien 0.5 BTC vaut en euros");
        System.out.println(result);

        System.out.println();
        System.out.println("Securite agents en production :");
        System.out.println("  - Sandboxer l'execution de code");
        System.out.println("  - Limiter les permissions des outils");
        System.out.println("  - Logger toutes les actions");
        System.out.println("  - Implementer un circuit breaker");
    }
}

// Java 11 avec LangChain4j — Pipeline multi-agents
import dev.langchain4j.model.openai.OpenAiChatModel;
import dev.langchain4j.service.AiServices;
import dev.langchain4j.service.SystemMessage;
import dev.langchain4j.service.UserMessage;

public class MultiAgentsPipeline {

    // Agent 1 : Architecte logiciel
    interface Architect {
        @SystemMessage("Tu es un architecte logiciel senior Java/Spring. " +
            "Propose une architecture claire et robuste. Ne code pas toi-meme.")
        String design(@UserMessage String requirement);
    }

    // Agent 2 : Développeur
    interface Developer {
        @SystemMessage("Tu es un developpeur senior Java 11. " +
            "Implemente ce que l'architecte a concu. Code complet, type, teste.")
        String implement(@UserMessage String architecture);
    }

    // Agent 3 : Reviewer
    interface Reviewer {
        @SystemMessage("Tu es un expert en code review et securite Java. " +
            "Valide le code. Repond APPROVED quand le code est pret pour la prod.")
        String review(@UserMessage String code);
    }

    public static void main(String[] args) {
        OpenAiChatModel llm = OpenAiChatModel.builder()
            .apiKey(System.getenv("OPENAI_API_KEY"))
            .modelName("gpt-4o")
            .temperature(0.0)
            .build();

        Architect architect = AiServices.create(Architect.class, llm);
        Developer developer = AiServices.create(Developer.class, llm);
        Reviewer  reviewer  = AiServices.create(Reviewer.class,  llm);

        String task = "API Spring Boot avec authentification JWT et CRUD utilisateurs";

        System.out.println("=== ARCHITECTE ===");
        String architecture = architect.design(task);
        System.out.println(architecture);

        System.out.println();
        System.out.println("=== DÉVELOPPEUR ===");
        String code = developer.implement(architecture);
        System.out.println(code);

        System.out.println();
        System.out.println("=== REVIEWER ===");
        String verdict = reviewer.review(code);
        System.out.println(verdict);
    }
}

