from langchain.agents import AgentExecutor, create_react_agent
from langchain.tools import tool
from langchain_anthropic import ChatAnthropic
from langchain import hub

@tool
def recherche_web(query: str) -> str:
    """Recherche des informations sur le web. Utiliser pour les faits récents."""
    return f'Résultats simulés pour : {query}'

@tool
def calculer(expression: str) -> str:
    """Évalue une expression mathématique Python. Ex: 2**10 ou sum([1,2,3])."""
    try:
        result = eval(expression, {'__builtins__': {}}, {'sum': sum, 'max': max, 'min': min})
        return str(result)
    except Exception as e:
        return f'Erreur : {e}'

@tool
def lire_fichier(chemin: str) -> str:
    """Lit le contenu d'un fichier texte (2000 premiers caractères)."""
    try:
        with open(chemin, 'r', encoding='utf-8') as f:
            return f.read()[:2000]
    except FileNotFoundError:
        return f'Fichier non trouvé : {chemin}'

llm = ChatAnthropic(model='claude-opus-4-6')
tools = [recherche_web, calculer, lire_fichier]
prompt = hub.pull('hwchase17/react')
agent = create_react_agent(llm, tools, prompt)
agent_executor = AgentExecutor(agent=agent, tools=tools, verbose=True, max_iterations=5)

resultat = agent_executor.invoke({'input': 'Calcule 2^32 et explique ce nombre.'})
print(f'Réponse : {resultat["output"]}')

