// Java 11 avec le SDK MCP officiel (io.modelcontextprotocol:sdk:0.7.0)
import com.fasterxml.jackson.databind.ObjectMapper;
import io.modelcontextprotocol.server.McpServer;
import io.modelcontextprotocol.server.McpServerFeatures;
import io.modelcontextprotocol.server.transport.StdioServerTransport;
import io.modelcontextprotocol.spec.McpSchema.*;
import java.util.*;

public class MCPServeurMetier {
    static final ObjectMapper mapper = new ObjectMapper();

    public static void main(String[] args) throws Exception {
        McpServer server = McpServer.sync(new StdioServerTransport())
            .serverInfo("mon-serveur-metier", "1.0.0")
            .capabilities(ServerCapabilities.builder()
                .tools(new ServerCapabilities.Tools(false))
                .build())
            .build();

        // Outil 1 : Informations produit par SKU
        server.addTool(
            new Tool("get_product_info",
                "Recupere les infos d'un produit par son SKU",
                buildSchema(Map.of("sku", "string"))),
            (exchange, toolArgs) -> {
                String sku = (String) toolArgs.get("sku");
                Map<String, Object> product = Map.of(
                    "sku", sku, "name", "Produit Demo", "price", 29.99);
                try {
                    return new CallToolResult(
                        List.of(new TextContent(mapper.writeValueAsString(product))), false);
                } catch (Exception e) { throw new RuntimeException(e); }
            }
        );

        // Outil 2 : Vérification du stock
        server.addTool(
            new Tool("check_stock",
                "Verifie le stock disponible d'un produit",
                buildSchema(Map.of("sku", "string", "warehouse", "string"))),
            (exchange, toolArgs) -> {
                String sku = (String) toolArgs.get("sku");
                String warehouse = (String) toolArgs.getOrDefault("warehouse", "PARIS");
                Map<String, Object> stock = Map.of(
                    "sku", sku, "warehouse", warehouse, "quantity", 42);
                try {
                    return new CallToolResult(
                        List.of(new TextContent(mapper.writeValueAsString(stock))), false);
                } catch (Exception e) { throw new RuntimeException(e); }
            }
        );

        server.connect(server.getTransport());
        System.err.println("Serveur MCP demarré — en attente de connexions");

        // claude_desktop_config.json :
        // "mcpServers": { "mon-serveur": { "command": "java", "args": ["-jar","server.jar"] } }
    }

    static JsonSchema buildSchema(Map<String, String> props) {
        Map<String, Object> properties = new HashMap<>();
        props.forEach((k, v) -> properties.put(k, Map.of("type", v)));
        return new JsonSchema("object", properties, new ArrayList<>(props.keySet()));
    }
}

