# pip install mcp
from mcp.server import Server
from mcp.server.models import InitializationOptions
from mcp.types import Tool, TextContent, CallToolResult
import mcp.server.stdio as stdio
import json

app = Server('mon-serveur-mcp')

@app.list_tools()
async def list_tools() -> list[Tool]:
    return [
        Tool(
            name='rechercher_meteo',
            description='Obtenir la météo actuelle d\'une ville française.',
            inputSchema={
                'type': 'object',
                'properties': {
                    'ville': {'type': 'string', 'description': 'Nom de la ville'}
                },
                'required': ['ville']
            }
        ),
        Tool(
            name='lire_fichier_csv',
            description='Lit un fichier CSV et retourne les premières lignes.',
            inputSchema={
                'type': 'object',
                'properties': {
                    'chemin': {'type': 'string'},
                    'lignes': {'type': 'number', 'default': 10}
                },
                'required': ['chemin']
            }
        ),
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict) -> CallToolResult:
    if name == 'rechercher_meteo':
        ville = arguments['ville']
        return CallToolResult(content=[TextContent(type='text',
            text=f'Météo à {ville} : 18°C, partiellement nuageux')])
    elif name == 'lire_fichier_csv':
        import csv
        chemin = arguments['chemin']
        n = int(arguments.get('lignes', 10))
        try:
            with open(chemin, 'r', encoding='utf-8') as f:
                rows = list(csv.DictReader(f))[:n]
            return CallToolResult(content=[TextContent(type='text',
                text=json.dumps(rows, ensure_ascii=False, indent=2))])
        except FileNotFoundError:
            return CallToolResult(content=[TextContent(type='text',
                text=f'Fichier non trouvé : {chemin}')])
    return CallToolResult(content=[TextContent(type='text', text=f'Outil inconnu : {name}')])

if __name__ == '__main__':
    import asyncio
    asyncio.run(stdio.run(app, InitializationOptions(server_name='mon-serveur-mcp', server_version='1.0')))

