from mcp.server import Server
from mcp.types import Tool, TextContent, CallToolResult
import sqlite3, json

app = Server('db-assistant')
DB_PATH = 'ma_base.db'

@app.list_tools()
async def list_tools():
    return [Tool(
        name='executer_sql',
        description='Exécute une requête SQL SELECT en lecture seule sur la base de données.',
        inputSchema={
            'type': 'object',
            'properties': {'query': {'type': 'string', 'description': 'Requête SQL SELECT'}},
            'required': ['query']
        }
    )]

@app.call_tool()
async def call_tool(name: str, args: dict):
    if name == 'executer_sql':
        query = args['query'].strip()
        if not query.upper().startswith('SELECT'):
            return CallToolResult(content=[TextContent(type='text',
                text='Erreur : seules les requêtes SELECT sont autorisées')])
        try:
            conn = sqlite3.connect(DB_PATH)
            cursor = conn.execute(query)
            colonnes = [desc[0] for desc in cursor.description]
            lignes = cursor.fetchmany(50)
            conn.close()
            result = {'colonnes': colonnes, 'lignes': lignes}
            return CallToolResult(content=[TextContent(type='text',
                text=json.dumps(result, ensure_ascii=False, indent=2))])
        except Exception as e:
            return CallToolResult(content=[TextContent(type='text', text=f'Erreur SQL : {e}')])
